-- Additive research-to-Clyde strategy automation. No raw report text is stored here.
create table if not exists public.credit_strategy_sources (id uuid primary key default gen_random_uuid(), source_type text not null, title text not null, creator text, source_reference text, publication_date date, content_hash text not null unique, category text not null default 'credit_strategy', source_confidence text not null default 'low', review_status text not null default 'queued' check (review_status in ('queued','processing','needs_verification','needs_approval','approved','rejected','failed')), metadata jsonb not null default '{}'::jsonb, last_reviewed_at timestamptz, created_at timestamptz not null default now());
create table if not exists public.credit_strategy_claims (id uuid primary key default gen_random_uuid(), source_id uuid not null references public.credit_strategy_sources(id) on delete cascade, summarized_claim text not null, account_category text, strategy_category text, claimed_outcome text, claimed_time_frame text, conditions jsonb not null default '[]'::jsonb, evidence_type text, official_support_status text not null default 'unverified', risk_score integer not null default 50 check (risk_score between 0 and 100), promotional_language boolean not null default false, disposition text not null default 'under_review' check (disposition in ('under_review','approved','conditional','practitioner','rejected')), review_notes text, created_at timestamptz not null default now());
create table if not exists public.credit_strategy_definitions (id text primary key, name text not null, description text not null, applicable_categories jsonb not null default '[]'::jsonb, client_education_copy text not null, required_report_facts jsonb not null default '[]'::jsonb, optional_client_confirmations jsonb not null default '[]'::jsonb, required_evidence jsonb not null default '[]'::jsonb, draft_tools jsonb not null default '[]'::jsonb, expected_process jsonb not null default '[]'::jsonb, possible_outcomes text not null, limitations text not null, risks text not null, official_support_summary text, practitioner_evidence_summary text, prohibited_claims jsonb not null default '[]'::jsonb, version integer not null default 1, approval_status text not null check (approval_status in ('discovered','under_review','conditionally_approved','approved_for_education','approved_for_tool_use','rejected','retired')), approved_at timestamptz, approved_by uuid, review_expires_at timestamptz, updated_at timestamptz not null default now());
create table if not exists public.credit_strategy_source_links (strategy_id text not null references public.credit_strategy_definitions(id), source_id uuid not null references public.credit_strategy_sources(id), claim_id uuid references public.credit_strategy_claims(id), support_type text not null default 'discovery', primary key(strategy_id,source_id,claim_id));
create table if not exists public.credit_strategy_recommendations (id uuid primary key default gen_random_uuid(), tenant_id text not null, client_id text not null, document_id text not null, parser_result_id uuid, system_review_id uuid, canonical_account_id text not null, discrepancy_id text, strategy_id text not null, strategy_version integer not null, status text not null default 'generated', client_visible boolean not null default false, confidence text not null, payload jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.credit_strategy_client_decisions (id uuid primary key default gen_random_uuid(), recommendation_id uuid not null references public.credit_strategy_recommendations(id) on delete cascade, tenant_id text not null, client_id text not null, actor_type text not null check (actor_type in ('system','client','admin','Clyde')), actor_id uuid, decision text not null check (decision in ('viewed','selected','declined','saved','evidence_requested','evidence_uploaded','draft_requested','draft_reviewed','authorized','escalated')), notes text, previous_state jsonb not null default '{}'::jsonb, new_state jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists public.credit_strategy_tool_requests (id uuid primary key default gen_random_uuid(), recommendation_id uuid not null references public.credit_strategy_recommendations(id), tenant_id text not null, client_id text not null, tool_type text not null, status text not null default 'requested', client_authorized boolean not null default false, docupost_authorized boolean not null default false, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.credit_strategy_outcomes (id uuid primary key default gen_random_uuid(), recommendation_id uuid not null references public.credit_strategy_recommendations(id), strategy_id text not null, strategy_version integer not null, account_category text, discrepancy_category text, bureau_category text, furnisher_category text, selected_option text, draft_sent boolean not null default false, response_type text, time_to_response_days integer, follow_up_required boolean, readiness_effect text, created_at timestamptz not null default now());

insert into public.credit_strategy_definitions (id,name,description,applicable_categories,client_education_copy,possible_outcomes,limitations,risks,approval_status,approved_at,review_expires_at)
select id,name,'Controlled funding-readiness education and tool workflow.',jsonb_build_array(category),'Nexus explains report facts, options, evidence needs, and approval gates.', 'Reporting may be confirmed, corrected, updated, or remain unchanged.','No correction, removal, score change, or funding decision is guaranteed.','Use only when report facts and client confirmations support the strategy.',approval,now(),now()+interval '1 year' from (values
('cross_bureau_balance_review','Cross-Bureau Balance Review','balance_mismatch','approved_for_tool_use'),('cross_bureau_date_review','Cross-Bureau Date Review','date_mismatch','approved_for_tool_use'),('cross_bureau_status_review','Cross-Bureau Status Review','status_mismatch','approved_for_tool_use'),('duplicate_account_review','Duplicate Account Review','duplicate_possible','approved_for_tool_use'),('account_ownership_review','Account Ownership Review','ownership_mismatch','approved_for_education'),('original_creditor_request','Original Creditor Information Request','original_creditor_missing','approved_for_tool_use'),('debt_validation_education','Debt Validation Education','debt_validation','approved_for_education'),('purchased_debt_documentation','Purchased Debt Documentation Review','purchased_debt_documentation','approved_for_tool_use'),('chain_of_title_request','Chain-of-Title Documentation Request','chain_of_title','approved_for_tool_use'),('unauthorized_inquiry_review','Unauthorized Inquiry Review','unauthorized_inquiry','approved_for_tool_use'),('personal_information_correction','Personal Information Correction','personal_info_mismatch','approved_for_tool_use'),('incorrect_limit_review','Incorrect Limit/High-Limit Review','limit_mismatch','approved_for_tool_use'),('incorrect_payment_status_review','Incorrect Payment Status Review','payment_status_mismatch','approved_for_tool_use'),('paid_settled_status_review','Paid/Settled Status Review','paid_settled_status','approved_for_tool_use'),('collection_resolution','Collection Resolution Options','accurate_collection','approved_for_education'),('goodwill_request','Goodwill Request Education','goodwill','approved_for_education'),('settlement_preparation','Settlement Preparation','settlement','approved_for_education'),('pay_for_delete_education','Pay-for-Delete Negotiation Education','pay_for_delete','approved_for_education'),('utilization_optimization','Utilization Optimization Plan','high_utilization','approved_for_education'),('statement_date_optimization','Statement-Date Optimization','statement_date','approved_for_education'),('limit_increase_considerations','Credit-Limit Increase Considerations','limit_increase','approved_for_education'),('positive_history_building','Positive History Building','positive_history','approved_for_education'),('aging_timing','Aging/Timing Strategy','aging','approved_for_education'),('complaint_escalation','Complaint or Escalation Education','complaint','approved_for_education'),('no_dispute_optimization','No-Dispute Funding Optimization','no_action_suggested','approved_for_education')) as seed(id,name,category,approval)
on conflict (id) do update set name=excluded.name, description=excluded.description, applicable_categories=excluded.applicable_categories, client_education_copy=excluded.client_education_copy, possible_outcomes=excluded.possible_outcomes, limitations=excluded.limitations, risks=excluded.risks, approval_status=excluded.approval_status, updated_at=now();

create index if not exists credit_strategy_recommendations_client_idx on public.credit_strategy_recommendations(tenant_id,client_id,created_at desc); create index if not exists credit_strategy_recommendations_document_idx on public.credit_strategy_recommendations(document_id); create index if not exists credit_strategy_decisions_recommendation_idx on public.credit_strategy_client_decisions(recommendation_id,created_at); create index if not exists credit_strategy_claims_source_idx on public.credit_strategy_claims(source_id);
alter table public.credit_strategy_sources enable row level security; alter table public.credit_strategy_claims enable row level security; alter table public.credit_strategy_definitions enable row level security; alter table public.credit_strategy_source_links enable row level security; alter table public.credit_strategy_recommendations enable row level security; alter table public.credit_strategy_client_decisions enable row level security; alter table public.credit_strategy_tool_requests enable row level security; alter table public.credit_strategy_outcomes enable row level security;
create policy credit_strategy_research_admin on public.credit_strategy_sources for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin()); create policy credit_strategy_claims_admin on public.credit_strategy_claims for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin()); create policy credit_strategy_definitions_read on public.credit_strategy_definitions for select to authenticated using (approval_status in ('approved_for_education','approved_for_tool_use') or public.nexus_is_active_admin()); create policy credit_strategy_definitions_admin on public.credit_strategy_definitions for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin()); create policy credit_strategy_links_admin on public.credit_strategy_source_links for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin());
create policy credit_strategy_recommendations_select on public.credit_strategy_recommendations for select to authenticated using (public.nexus_is_active_admin() or (client_visible and exists(select 1 from public.tenant_memberships tm where tm.user_id=auth.uid() and tm.tenant_id=credit_strategy_recommendations.tenant_id and tm.client_id=credit_strategy_recommendations.client_id))); create policy credit_strategy_recommendations_admin on public.credit_strategy_recommendations for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin());
create policy credit_strategy_decisions_select on public.credit_strategy_client_decisions for select to authenticated using (public.nexus_is_active_admin() or exists(select 1 from public.tenant_memberships tm where tm.user_id=auth.uid() and tm.tenant_id=credit_strategy_client_decisions.tenant_id and tm.client_id=credit_strategy_client_decisions.client_id)); create policy credit_strategy_decisions_insert on public.credit_strategy_client_decisions for insert to authenticated with check (public.nexus_is_active_admin() or (actor_type='client' and exists(select 1 from public.tenant_memberships tm where tm.user_id=auth.uid() and tm.tenant_id=credit_strategy_client_decisions.tenant_id and tm.client_id=credit_strategy_client_decisions.client_id)));
create policy credit_strategy_tools_select on public.credit_strategy_tool_requests for select to authenticated using (public.nexus_is_active_admin() or exists(select 1 from public.tenant_memberships tm where tm.user_id=auth.uid() and tm.tenant_id=credit_strategy_tool_requests.tenant_id and tm.client_id=credit_strategy_tool_requests.client_id)); create policy credit_strategy_tools_client_insert on public.credit_strategy_tool_requests for insert to authenticated with check (public.nexus_is_active_admin() or exists(select 1 from public.tenant_memberships tm where tm.user_id=auth.uid() and tm.tenant_id=credit_strategy_tool_requests.tenant_id and tm.client_id=credit_strategy_tool_requests.client_id)); create policy credit_strategy_outcomes_admin on public.credit_strategy_outcomes for all to authenticated using (public.nexus_is_active_admin()) with check (public.nexus_is_active_admin());
grant select,insert,update on public.credit_strategy_sources,public.credit_strategy_claims,public.credit_strategy_definitions,public.credit_strategy_source_links,public.credit_strategy_recommendations,public.credit_strategy_client_decisions,public.credit_strategy_tool_requests,public.credit_strategy_outcomes to authenticated;
